import React from "react";
import Jumbotron from 'react-bootstrap/Jumbotron';
import Container from 'react-bootstrap/Container';
import "../styles/reviews.css";
import "../index.css";
import Header from "../components/Header.js"
import Footer from "../components/Footer.js"
import FilmCard from '../components/FilmCard';
import CardGroup from 'react-bootstrap/CardGroup';


// {
//     film:
//     url: 
//     reviewp1: 
//     reviewp2: 
//     image:
//   },

const filmDetails = [
    {
      film: 'The Incredibles 2',
      url: 'http://hdqwalls.com/the-incredibles-2-2018-poster-wallpaper',
      image: '../images/filmImages/incredibles2.jpg',
      date: "August 2018"
    },
    {
        film: "The Darkest Minds",
        url: "https://www.foxmovies.com/movies/the-darkest-minds",
        image: "../images/filmImages/theDM.jpg",
        date: "August 2018"
    }
  ]
class Contact extends React.Component {

    renderReviews() {
        let filmCards = filmDetails.map((content) => {
            return <FilmCard film={content.film} url={content.url} image={content.image} date={content.date}/>
        });

        return (
          <>
            <CardGroup>
              {filmCards}
            </CardGroup>
          </>
        );
      }



    render() {
        return (
            <div id="reviews" className="page">
                <Header />
                <Jumbotron fluid>
                    <Container>
                        <h1>Film Reviews</h1>
                            <p className="card-text">
                                This page contains my reviews on films that have 
                                been released recently or ones that I've just watched 
                                for the first time. I write these for fun!
                            </p>
                    </Container>
                </Jumbotron>
                {this.renderReviews()}
                <Footer />
            </div>

        );
    }
}

export default Contact;
